// server/services/github-service.ts
var GITHUB_PAT = process.env.GITHUB_PAT ?? "";
var GITHUB_OWNER = process.env.GITHUB_REPO_OWNER ?? "";
var GITHUB_REPO = process.env.GITHUB_REPO_NAME ?? "";
var GITHUB_API = "https://api.github.com";
async function githubRequest(method, path2, body, retries = 3) {
  if (!GITHUB_PAT) {
    throw new Error("GITHUB_PAT not configured. Set it in .env to enable GitHub integration.");
  }
  for (let attempt = 1; attempt <= retries; attempt++) {
    const res = await fetch(`${GITHUB_API}${path2}`, {
      method,
      headers: {
        Authorization: `Bearer ${GITHUB_PAT}`,
        Accept: "application/vnd.github+json",
        "X-GitHub-Api-Version": "2022-11-28",
        "Content-Type": "application/json",
        "User-Agent": "bug-triage-max/1.0"
      },
      ...body ? { body: JSON.stringify(body) } : {}
    });
    const rateLimit = {
      remaining: parseInt(res.headers.get("X-RateLimit-Remaining") ?? "60", 10),
      reset: parseInt(res.headers.get("X-RateLimit-Reset") ?? "0", 10)
    };
    if (res.status === 429 || res.status === 403 && rateLimit.remaining === 0) {
      const waitMs = rateLimit.reset * 1e3 - Date.now() + 1e3;
      console.warn(`[GitHub] Rate limited. Waiting ${Math.round(waitMs / 1e3)}s...`);
      await new Promise((r) => setTimeout(r, Math.max(waitMs, 5e3)));
      continue;
    }
    if (!res.ok) {
      const errBody = await res.text();
      if (attempt === retries) {
        throw new Error(`GitHub API ${res.status}: ${errBody}`);
      }
      await new Promise((r) => setTimeout(r, 1e3 * attempt));
      continue;
    }
    const data = await res.json();
    return { data, rateLimit };
  }
  throw new Error("GitHub API: all retries exhausted");
}
async function createGitHubIssue(params) {
  if (!GITHUB_OWNER || !GITHUB_REPO) {
    throw new Error("GITHUB_REPO_OWNER and GITHUB_REPO_NAME must be set in .env");
  }
  const { data } = await githubRequest(
    "POST",
    `/repos/${GITHUB_OWNER}/${GITHUB_REPO}/issues`,
    {
      title: params.title,
      body: params.body,
      labels: params.labels ?? ["bug", "triage-max"]
    }
  );
  return { number: data.number, url: data.html_url, id: data.id };
}
async function getGitHubIssue(issueNumber) {
  if (!GITHUB_OWNER || !GITHUB_REPO) return null;
  try {
    const { data } = await githubRequest(
      "GET",
      `/repos/${GITHUB_OWNER}/${GITHUB_REPO}/issues/${issueNumber}`
    );
    return {
      number: data.number,
      url: data.html_url,
      state: data.state,
      title: data.title
    };
  } catch {
    return null;
  }
}
async function createDraftRelease(params) {
  if (!GITHUB_OWNER || !GITHUB_REPO) return null;
  try {
    const { data } = await githubRequest(
      "POST",
      `/repos/${GITHUB_OWNER}/${GITHUB_REPO}/releases`,
      {
        tag_name: params.tagName,
        name: params.name,
        body: params.body,
        draft: true,
        prerelease: false
      }
    );
    return { id: data.id, url: data.html_url };
  } catch (err) {
    console.error("[GitHub] createDraftRelease failed:", err);
    return null;
  }
}
async function checkRateLimit() {
  if (!GITHUB_PAT) return null;
  try {
    const { rateLimit } = await githubRequest(
      "GET",
      "/rate_limit"
    );
    return rateLimit;
  } catch {
    return null;
  }
}
var githubConfigured = !!(GITHUB_PAT && GITHUB_OWNER && GITHUB_REPO);

